import{_ as i,c as o,o as n,ah as e}from"./chunks/framework.DwHsq7Fg.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/rate-limiting.md","filePath":"basics_api/rate-limiting.md"}'),r={name:"basics_api/rate-limiting.md"};function s(g,t,l,a,p,c){return n(),o("div",null,t[0]||(t[0]=[e('<h3 id="🚦-rate-limiting-обмеження-швидкості-захист-api-від-зловживання-та-перевантаження" tabindex="-1">🚦 Rate Limiting (Обмеження швидкості): Захист API від зловживання та перевантаження <a class="header-anchor" href="#🚦-rate-limiting-обмеження-швидкості-захист-api-від-зловживання-та-перевантаження" aria-label="Permalink to “🚦 Rate Limiting (Обмеження швидкості): Захист API від зловживання та перевантаження”">​</a></h3><p><strong>Що це?</strong></p><p>Rate Limiting (обмеження швидкості), також відоме як throttling (регулювання), - це <strong>механізм контролю кількості запитів</strong>, які клієнт (ідентифікований за IP-адресою, API-ключем, токеном користувача тощо) може зробити до API протягом певного періоду часу. Це як встановлення <strong>лічильника використання</strong> ⏱️ для кожного клієнта, щоб запобігти зловживанню ресурсами API та забезпечити його стабільну роботу для всіх користувачів.</p><p><strong>Як це працює?</strong></p><p>Сервер API реалізує політику обмеження швидкості, яка визначає:</p><ul><li><strong>Ліміт запитів:</strong> Максимальна кількість запитів, яку клієнт може зробити.</li><li><strong>Часове вікно:</strong> Період часу, протягом якого діє ліміт (наприклад, за секунду, за хвилину, за годину, за день).</li><li><strong>Критерії ідентифікації клієнта:</strong> Спосіб ідентифікації клієнта для застосування ліміту (наприклад, IP-адреса, API-ключ, ідентифікатор користувача, токен).</li><li><strong>Дія при перевищенні ліміту:</strong> Що відбувається, коли клієнт перевищує встановлений ліміт (наприклад, блокування подальших запитів, повернення помилки).</li></ul><p>Коли клієнт надсилає запит до API, сервер перевіряє, чи не перевищив цей клієнт встановлений ліміт протягом поточного часового вікна. Якщо ліміт не перевищено, запит обробляється. Якщо ліміт перевищено, сервер відхиляє запит і повертає клієнту код помилки <code>429 Too Many Requests</code> (або інший відповідний код), часто з додатковими заголовками, що вказують, коли клієнт зможе зробити наступний запит (наприклад, заголовок <code>Retry-After</code>).</p><p><strong>Переваги Rate Limiting:</strong></p><ul><li><strong>Захист від DoS/DDoS атак:</strong> Обмежуючи кількість запитів з однієї точки, rate limiting допомагає запобігти атакам типу &quot;відмова в обслуговуванні&quot; (Denial of Service) або розподіленим атакам (Distributed Denial of Service), коли зловмисники намагаються перевантажити API великою кількістю запитів, роблячи його недоступним для легітимних користувачів.</li><li><strong>Запобігання зловживанню API:</strong> Обмежує можливість окремих користувачів або програм надмірно використовувати ресурси API (наприклад, парсинг великих обсягів даних за короткий проміжок часу).</li><li><strong>Забезпечення справедливого використання:</strong> Гарантує, що всі клієнти мають рівномірний доступ до ресурсів API та жоден клієнт не монополізує їх.</li><li><strong>Контроль витрат на інфраструктуру:</strong> Допомагає контролювати витрати на сервери та пропускну здатність, пов&#39;язані з використанням API.</li><li><strong>Підтримка якості обслуговування (QoS):</strong> Забезпечує стабільну та передбачувану роботу API для всіх користувачів.</li><li><strong>Запобігання помилкам бекенду:</strong> Обмеження кількості запитів може допомогти запобігти перевантаженню внутрішніх систем та їхнім збоям.</li></ul><p><strong>Реалізація Rate Limiting:</strong></p><p>Обмеження швидкості може бути реалізовано на різних рівнях інфраструктури:</p><ul><li><strong>На рівні веб-сервера:</strong> Модулі веб-серверів (наприклад, <code>mod_ratelimit</code> для Apache, <code>ngx_http_limit_req_module</code> для Nginx) можуть надавати базові можливості обмеження швидкості на основі IP-адрес.</li><li><strong>На рівні API Gateway:</strong> Шлюзи API (наприклад, AWS API Gateway, Kong, Apigee) часто мають вбудовані та гнучкі механізми обмеження швидкості, що дозволяють налаштовувати ліміти на основі різних критеріїв (API-ключ, токен користувача, IP-адреса, географічне розташування тощо).</li><li><strong>На рівні коду застосунку (бекенду):</strong> Логіка обмеження швидкості може бути реалізована безпосередньо в коді вашого API, використовуючи бази даних (наприклад, Redis, Memcached) або спеціалізовані бібліотеки для зберігання та перевірки лічильників запитів.</li></ul><p><strong>Стратегії Rate Limiting:</strong></p><p>Існують різні стратегії застосування обмеження швидкості:</p><ul><li><strong>Токеновий кошик (Token Bucket):</strong> Кожен клієнт має &quot;кошик&quot;, який періодично поповнюється &quot;токенами&quot;. Кожен запит &quot;витрачає&quot; один токен. Якщо в кошику немає токенів, запит відхиляється.</li><li><strong>Лічильник (Leaky Bucket):</strong> Для кожного клієнта ведеться лічильник кількості запитів протягом певного періоду часу. Якщо лічильник досягає ліміту, нові запити відхиляються. Лічильник періодично зменшується.</li><li><strong>Фіксоване вікно (Fixed Window):</strong> Встановлюється фіксований часовий інтервал (наприклад, хвилина). Кількість запитів клієнта протягом цього інтервалу обмежена. Після закінчення інтервалу лічильник скидається.</li><li><strong>Ковзне вікно (Sliding Window):</strong> Подібно до фіксованого вікна, але замість фіксованого інтервалу враховується часове вікно, що ковзає разом з кожним новим запитом. Це забезпечує більш точне обмеження швидкості.</li></ul><p><strong>Важливі аспекти Rate Limiting:</strong></p><ul><li><strong>Вибір правильних лімітів:</strong> Ліміти повинні бути достатньо високими, щоб не обмежувати легітимних користувачів, але достатньо низькими, щоб забезпечити захист від зловживання.</li><li><strong>Інформування клієнтів:</strong> API повинні чітко документувати свої політики обмеження швидкості, включаючи ліміти, часові вікна та дії при перевищенні ліміту.</li><li><strong>Надання інформації про обмеження у відповідях:</strong> Сервер повинен повертати інформативні заголовки (наприклад, <code>X-RateLimit-Limit</code>, <code>X-RateLimit-Remaining</code>, <code>X-RateLimit-Reset</code>) у відповідях, щоб клієнти могли відстежувати свої ліміти та уникати їх перевищення.</li><li><strong>Обробка помилок на стороні клієнта:</strong> Клієнтські додатки повинні коректно обробляти помилки <code>429 Too Many Requests</code> та реалізовувати стратегії повторних спроб з експоненціальною затримкою (exponential backoff).</li></ul><p><strong>Висновок:</strong></p><p>Rate Limiting є критично важливим заходом безпеки та забезпечення стабільності для будь-якого публічного або високонавантаженого API. Правильно налаштовані політики обмеження швидкості допомагають захистити API від зловживання, забезпечити справедливий доступ для всіх користувачів та підтримувати якість обслуговування.</p>',19)]))}const P=i(r,[["render",s]]);export{m as __pageData,P as default};
